function settingsContent(){const s=S.settings||{};const selected=function(name,value){return String(s[name]||'')===value?' selected':''};const checked=s.notifications===false?'':' checked';return '<div class="grid two"><section class="card"><div class="in"><h2>Workspace settings</h2><p class="muted">These settings are saved to your signed-in account and restored when you log back in.</p><form id="workspaceSettingsForm"><label>Workspace name</label><input name="workspaceName" value="'+esc(s.workspaceName||WORKSPACE_LABEL||'Personal workspace')+'"><label>Theme</label><select name="theme"><option value="white-blue"'+selected('theme','white-blue')+'>White and dark blue</option><option value="green-white"'+selected('theme','green-white')+'>Green and white</option><option value="compact-dark"'+selected('theme','compact-dark')+'>Compact dark</option></select><label>Layout density</label><select name="density"><option value="comfortable"'+selected('density','comfortable')+'>Comfortable</option><option value="compact"'+selected('density','compact')+'>Compact</option></select><label>Default CRM section</label><select name="defaultCrmView"><option value="overview"'+selected('defaultCrmView','overview')+'>Overview</option><option value="all"'+selected('defaultCrmView','all')+'>All Records</option><option value="Person"'+selected('defaultCrmView','Person')+'>Contacts</option><option value="Company"'+selected('defaultCrmView','Company')+'>Companies</option><option value="Deal"'+selected('defaultCrmView','Deal')+'>Deals</option><option value="Task"'+selected('defaultCrmView','Task')+'>Tasks</option><option value="Intake"'+selected('defaultCrmView','Intake')+'>Intakes</option><option value="Note"'+selected('defaultCrmView','Note')+'>Notes</option><option value="edit"'+selected('defaultCrmView','edit')+'>Edit Records</option></select><label style="display:flex;gap:8px;align-items:center;margin-top:10px"><input type="checkbox" name="notifications" value="true"'+checked+'> Save notification preference</label><br><button class="primary">Save settings</button><p class="status" id="settingsStatus"></p></form></div></section><section class="card"><div class="in"><h2>Account storage</h2><p class="muted">Records, plans, reports, analytics events, and settings are separated by your account workspace.</p><div class="item"><b>Workspace ID</b><p class="muted">'+esc(s.workspaceId||'Assigned when signed in')+'</p></div><div class="item"><b>Last saved</b><p class="muted">'+esc(s.updatedAt?s.updatedAt.slice(0,19).replace('T',' '):'Not saved yet')+'</p></div></div></section></div>'}
function crmCount(type){if(type==='all')return S.records.length;if(type==='ai-records')return (S.aiRecords||[]).length;if(type==='overview'||type==='edit')return '';return S.records.filter(function(r){return r.type===type}).length}
function crmShell(content){const items=[['overview','Overview'],['ai-records','Review &amp; Publish'],['all','All Records'],['Person','Contacts'],['Company','Companies'],['Deal','Deals'],['Task','Tasks'],['Intake','Intakes'],['Note','Notes'],['edit','Edit Records']];return '<div class="crmShell"><aside class="crmSide"><div class="crmSideTitle">CRM sections</div><p class="muted" style="margin:6px 4px 12px;font-size:13px;line-height:1.35"><b>Review &amp; Publish</b> is where you edit and approve AI-created drafts before they enter the CRM.</p>'+items.map(function(item){const id=item[0],label=item[1];return '<button class="crmTab '+(S.crmView===id?'active':'')+'" data-crm="'+id+'"><span>'+label+'</span><span>'+crmCount(id)+'</span></button>'}).join('')+'</aside><div>'+content+'</div></div>'}
