source = source.replace("async function load(){let out=await Promise.all([api('/api/dashboard/summary'),api('/api/records'),api('/api/sources'),api('/api/plans'),api('/api/reports'),api('/api/analytics/events')]);S.summary=out[0];S.records=out[1].records;S.sources=out[2].sources;S.snippet=out[2].snippet;S.plans=out[3].plans;S.reports=out[4].reports;S.events=out[5].events;syncNotifications()}", "async function load(){let out=await Promise.all([api('/api/dashboard/summary'),api('/api/records'),api('/api/sources'),api('/api/plans'),api('/api/reports'),api('/api/analytics/events')]);let optional=await Promise.allSettled([api('/api/settings'),api('/api/records/drafts'),api('/api/email-connections'),api('/api/connected-resources')]);S.summary=out[0];S.records=out[1].records;S.sources=out[2].sources;S.snippet=out[2].snippet;S.plans=out[3].plans;S.reports=out[4].reports;S.events=out[5].events;const settingsResult=optional[0].status==='fulfilled'?optional[0].value:null,draftsResult=optional[1].status==='fulfilled'?optional[1].value:null,emailResult=optional[2].status==='fulfilled'?optional[2].value:null,connectedResult=optional[3].status==='fulfilled'?optional[3].value:null;S.settings=(settingsResult&&settingsResult.settings)||S.settings||{};S.aiRecords=(draftsResult&&draftsResult.records)||S.aiRecords||[];S.connectedResources=(connectedResult&&connectedResult.resources)||S.connectedResources||[];if(emailResult&&typeof constravaPreferredEmailConnection==='function')constravaHydrateEmailConnection(constravaPreferredEmailConnection(emailResult.connections||[]));S.optionalLoadErrors=optional.filter(function(result){return result.status==='rejected'}).map(function(result){return result.reason&&result.reason.message||'Optional data unavailable'});if(!S.settingsLoaded){S.settingsLoaded=true;if(S.settings.defaultCrmView)S.crmView=S.settings.defaultCrmView}syncNotifications()}");
