const constravaTabLoadingClientCode = "function constravaTabLabel(name){return name==='crm'?'CRM':name==='resources'?'Connected Resources':name==='settings'?'Settings':name==='notifications'?'Notifications':'Analytics'}\nfunction constravaTabLoadingMarkup(name){const label=constravaTabLabel(name);return '<style>@keyframes constravaTabSpin{to{transform:rotate(360deg)}}</style><section class=\"card tabLoadingState\" style=\"min-height:260px;display:grid;place-items:center;text-align:center;border-radius:14px\"><div><span aria-hidden=\"true\" style=\"display:inline-block;width:34px;height:34px;border:3px solid #d9e3f2;border-top-color:#061a33;border-radius:999px;animation:constravaTabSpin .8s linear infinite;margin-bottom:12px\"></span><h2 style=\"margin:0;color:#061a33\">Loading '+esc(label)+'</h2><p class=\"muted\" style=\"margin:6px 0 0\">Refreshing the latest page data.</p></div></section>'}\nfunction constravaShowTabLoading(name){const target=document.getElementById('app');if(target)target.innerHTML=constravaTabLoadingMarkup(name)}";
